@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_aed92ff45eaa43b1a42f9986162fdf89.Client.Models
@using sv_aed92ff45eaa43b1a42f9986162fdf89.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h1>Shipment Tracker</h1>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <em>Loading shipment @TrackingNumber&hellip;</em>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p><strong>@_errorMessage</strong></p>
        <button class="btn btn-outline-danger mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">@_shipment.TrackingNumber</h5>
            <p><strong>Status:</strong> @_shipment.Status</p>
            <p><strong>Location:</strong> @_shipment.Location</p>
            <p><strong>Estimated Delivery:</strong> @_shipment.EstimatedDelivery.ToString("f")</p>
        </div>
    </div>

    <h4>Status History</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Timestamp</th>
                <th>Description</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Description</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        await CancelPendingAsync();

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Request was intentionally cancelled (navigation or dispose); do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    private async ValueTask CancelPendingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

